[PYTHON]
import xml.etree.ElementTree as ET

def parse_xml_config(config_file):
    tree = ET.parse(config_file)
    root = tree.getroot()
    settings = {}
    for setting in root.findall('.//setting'):
        name = setting.find('name').text
        value = setting.find('value').text
        settings[name] = value
    return settings
